            )}

            <div className={isFocusMode ? 'hidden' : ''}>
              {!isAudioPlaying && (
                <ScriptDisplay script={activeSentencePairs.map(p => p.russian).join('\n')} />
              )}
            </div>
            <AudioControls 
              sentencePairs={activeSentencePairs} 
