// Fisher-Yates (aka Knuth) Shuffle
function shuffleArray<T>(array: T[]): T[] {
  const newArray = [...array];
  for (let i = newArray.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [newArray[i], newArray[j]] = [newArray[j], newArray[i]];
  }
  return newArray;
}

interface AudioControlsProps {
  sentencePairs: SentencePair[] | null;
  basePauseDuration: number;
  isRandomOrder: boolean;
  maxSentencesToPlay: number | null;
  isDynamicPauseEnabled: boolean;
  isMakePauseEnabled: boolean;
  isContinueAfterTranslationEnabled: boolean;
  russianSpeed: number;
  englishSpeed: number;
  autoPlayOnMount?: boolean; // New prop to trigger auto-play
  onPlaybackStatusChange?: (isActive: boolean) => void;
  onPlaybackStart?: () => void;
  onSequenceFinished?: () => void; // New callback when current list finishes
  onEnterFocusMode?: () => void;
  onExitFocusMode?: () => void;
  isFocusMode?: boolean;
}

type PlaybackState = 
  | "idle" 
  | "announcing_question_cue_before_russian"
  | "paused_after_question_cue_before_russian"
  | "playing_russian" 
  | "paused_after_russian_before_english"
  | "playing_english" 
  | "finished";

const QUESTION_CUE = "Вопрос ";
const QUESTION_CUE_PAUSE_DURATION_MS = 1000; 

const PER_CHAR_PAUSE_MS = 50; 
const MAX_PAUSE_MS = 10000; 

export const AudioControls: React.FC<AudioControlsProps> = ({ 
  sentencePairs, 
  basePauseDuration, 
  isRandomOrder, 
  maxSentencesToPlay,
  isDynamicPauseEnabled,
  isMakePauseEnabled,
  isContinueAfterTranslationEnabled,
  russianSpeed,
  englishSpeed,
  autoPlayOnMount = false,
  onPlaybackStatusChange,
  onPlaybackStart,
  onSequenceFinished,
  onEnterFocusMode,
  onExitFocusMode,
  isFocusMode
}) => {
  const [canUseSpeechSynthesis, setCanUseSpeechSynthesis] = useState<boolean>(false);
  const [playbackState, setPlaybackState] = useState<PlaybackState>("idle");
  const [currentSentenceIndex, setCurrentSentenceIndex] = useState<number>(0);
  const [currentPlaybackOrder, setCurrentPlaybackOrder] = useState<SentencePair[] | null>(null);
  const [isUserPaused, setIsUserPaused] = useState<boolean>(false);
  const [audioError, setAudioError] = useState<string | null>(null);
  const [unplayedDeck, setUnplayedDeck] = useState<SentencePair[] | null>(null);
  const [isListening, setIsListening] = useState<boolean>(false);

  const pauseTimeoutRef = useRef<number | null>(null);
  const isMountedRef = useRef<boolean>(true);
  const lastCalculatedPauseMsRef = useRef<number>(basePauseDuration * 1000);
  const stateBeforeUserPauseRef = useRef<PlaybackState | null>(null);
  const recognitionRef = useRef<any>(null);

  // This effect initializes or resets the deck of sentences to play from.
  // It runs when the source sentences change or the random order preference is toggled.
  useEffect(() => {
    if (sentencePairs && sentencePairs.length > 0) {
      const newDeck = isRandomOrder ? shuffleArray([...sentencePairs]) : [...sentencePairs];
      setUnplayedDeck(newDeck);
    } else {
      setUnplayedDeck(null);
    }
  }, [sentencePairs, isRandomOrder]);


  useEffect(() => {
    isMountedRef.current = true;
    if (typeof window !== 'undefined' && window.speechSynthesis) {
      setCanUseSpeechSynthesis(true);
    }
    return () => {
      isMountedRef.current = false;
      if (typeof window !== 'undefined' && window.speechSynthesis) {
        window.speechSynthesis.cancel();
      }
      if (pauseTimeoutRef.current) {
        clearTimeout(pauseTimeoutRef.current);
      }
      if (recognitionRef.current) {
        recognitionRef.current.abort();
        recognitionRef.current = null;
      }
    };
  }, []);

  useEffect(() => {
    if (onPlaybackStatusChange) {
      const isActive = playbackState !== "idle" && playbackState !== "finished";
      onPlaybackStatusChange(isActive);
    }
  }, [playbackState, onPlaybackStatusChange]);

  const speak = useCallback((text: string, lang: string, onEndCallback: () => void) => {
    if (!canUseSpeechSynthesis || !isMountedRef.current || isUserPaused) {
        return;
    }

    window.speechSynthesis.cancel(); 

    if (text.trim() === '') {
        console.warn(`Skipping speech for lang ${lang} as text is empty after processing.`);
        if (isMountedRef.current) {
            onEndCallback(); 
        }
        return;
    }

    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = lang;
    if (lang === 'ru-RU') {
      utterance.rate = russianSpeed;
    } else if (lang === 'en-US') {
      utterance.rate = englishSpeed;
    } else {
      utterance.rate = 1;
    }

    utterance.onend = () => {
      if (isMountedRef.current) {
        onEndCallback();
      }
    };

    utterance.onerror = (event: SpeechSynthesisErrorEvent) => {
      if (!isMountedRef.current) {
        return; 
      }

      if (event.error === 'interrupted' || event.error === 'canceled') {
        console.warn(
          `SpeechSynthesisUtterance.onerror (handled interruption) - Lang: ${lang}, ErrorCode: ${event.error}, UtteranceText (first 100 chars): "${utterance.text.substring(0,100)}..."`,
          event
        );
        return; 
      }

      console.error(
        `SpeechSynthesisUtterance.onerror (unhandled error) - Lang: ${lang}, ErrorCode: ${event.error}, UtteranceText (first 100 chars): "${utterance.text.substring(0,100)}..."`,
        event
      );

      let errorMsg = `Audio playback error for language "${lang}".`;
      if (event.error) {
        switch (event.error) {
          case 'language-unavailable':
          case 'voice-unavailable':
            errorMsg += ` The selected language or voice may not be supported by your browser. (Code: ${event.error})`;
            break;
          case 'synthesis-failed':
            errorMsg += ` Speech synthesis failed. This can sometimes be a temporary browser issue. (Code: ${event.error})`;
            break;
          case 'audio-busy':
            errorMsg += ` The audio system is busy. Please try again. (Code: ${event.error})`;
            break;
          case 'audio-hardware':
            errorMsg += ` There might be an issue with your audio hardware. (Code: ${event.error})`;
            break;
          case 'network':
            errorMsg += ` A network error occurred while trying to synthesize speech. (Code: ${event.error})`;
            break;
          case 'text-too-long':
             errorMsg += ` The text to speak was too long. (Code: ${event.error})`;
            break;
          case 'invalid-argument':
             errorMsg += ` An invalid argument was provided to the speech engine (e.g. rate, pitch). (Code: ${event.error})`;
            break;
          default:
            errorMsg += ` Details: ${event.error}.`;
        }
      } else {
        errorMsg += ` An unknown speech synthesis error occurred.`;
      }

      setAudioError(errorMsg);
      setPlaybackState("idle"); 
      setCurrentPlaybackOrder(null);
      setCurrentSentenceIndex(0);
      setIsUserPaused(false);
      onExitFocusMode?.();
    };
    window.speechSynthesis.speak(utterance);
  }, [canUseSpeechSynthesis, russianSpeed, englishSpeed, isUserPaused, onExitFocusMode]);

  const handleStop = useCallback(() => {
    if (!canUseSpeechSynthesis) return;
    window.speechSynthesis.cancel();
    if (pauseTimeoutRef.current) {
      clearTimeout(pauseTimeoutRef.current);
      pauseTimeoutRef.current = null;
    }
    if (recognitionRef.current) {
      recognitionRef.current.abort();
      recognitionRef.current = null;
    }
    setIsListening(false);
    setPlaybackState("idle");
    setCurrentSentenceIndex(0); 
    setCurrentPlaybackOrder(null);
    setIsUserPaused(false); 
    stateBeforeUserPauseRef.current = null;
    setAudioError(null);
    onExitFocusMode?.();
  }, [canUseSpeechSynthesis, onExitFocusMode]);

  const handlePlay = useCallback(async () => {
    if (!sentencePairs || sentencePairs.length === 0 || !canUseSpeechSynthesis) return;

    onPlaybackStart?.();
    onEnterFocusMode?.();

    setAudioError(null);
    setIsUserPaused(false);
    setIsListening(false);
    stateBeforeUserPauseRef.current = null;
    window.speechSynthesis.cancel();
    if (pauseTimeoutRef.current) {
      clearTimeout(pauseTimeoutRef.current);
      pauseTimeoutRef.current = null;
    }
    if (recognitionRef.current) {
      recognitionRef.current.abort();
      recognitionRef.current = null;
    }

    let currentDeck = unplayedDeck;

    // If the deck is empty or null, a full cycle was completed. Reset it for a new cycle.
    if (!currentDeck || currentDeck.length === 0) {
      currentDeck = isRandomOrder ? shuffleArray([...sentencePairs]) : [...sentencePairs];
    }

    const numToPlay = maxSentencesToPlay !== null && maxSentencesToPlay > 0
      ? Math.min(maxSentencesToPlay, currentDeck.length)
      : currentDeck.length;

    const orderToPlay = currentDeck.slice(0, numToPlay);
    const remainingDeck = currentDeck.slice(numToPlay);

    // Update the state with the remaining sentences for the next play session.
    setUnplayedDeck(remainingDeck);

    if (orderToPlay.length === 0) {
        setPlaybackState("finished");
        setCurrentPlaybackOrder(null);
        setCurrentSentenceIndex(0);
        onExitFocusMode?.();
        return;
    }

    setCurrentPlaybackOrder(orderToPlay);
    setCurrentSentenceIndex(0);

    const firstPairForPauseCalc = orderToPlay[0];
    const firstBasePauseMs = basePauseDuration * 1000;
    let initialPauseCalc = firstBasePauseMs;
    if (isDynamicPauseEnabled) {
      const firstRussianSentenceLength = firstPairForPauseCalc.russian.length;
      const firstDynamicPortionMs = firstRussianSentenceLength * PER_CHAR_PAUSE_MS;
      initialPauseCalc = Math.min(MAX_PAUSE_MS, firstBasePauseMs + firstDynamicPortionMs);
    }
    lastCalculatedPauseMsRef.current = initialPauseCalc;

    const firstPair = orderToPlay[0];
    const firstEnglishAfterMetadata = removeLeadingMetadata(firstPair.english);
    if (firstEnglishAfterMetadata.endsWith('?')) {
      setPlaybackState("announcing_question_cue_before_russian");
    } else {
      setPlaybackState("playing_russian");
    }

  }, [unplayedDeck, sentencePairs, canUseSpeechSynthesis, isRandomOrder, maxSentencesToPlay, basePauseDuration, isDynamicPauseEnabled, onPlaybackStart, onEnterFocusMode, onExitFocusMode]);


  // Clean up and reset when props change
  useEffect(() => {
    handleStop();

    // Auto-play logic for sequential file playback
    // If the parent says we should auto-play (because it just switched files),
    // we trigger play after a short delay to ensure state is clean.
    if (autoPlayOnMount && sentencePairs && sentencePairs.length > 0) {
        const timer = setTimeout(() => {
            handlePlay();
        }, 100);
        return () => clearTimeout(timer);
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [sentencePairs, maxSentencesToPlay, basePauseDuration, isDynamicPauseEnabled, isContinueAfterTranslationEnabled, russianSpeed, englishSpeed, autoPlayOnMount]);


  useEffect(() => {
    if (!isMountedRef.current || !currentPlaybackOrder || !canUseSpeechSynthesis) {
      return;
    }

    if (isUserPaused) { 
        return;
    }

    const isPlaybackBeyondPairs = currentSentenceIndex >= currentPlaybackOrder.length;

    if ((isPlaybackBeyondPairs || currentPlaybackOrder.length === 0) && playbackState !== "idle" && playbackState !== "finished") {
        setPlaybackState("finished");
        // Trigger callback when finished to allow parent to move to next file
        if (onSequenceFinished) onSequenceFinished();
        onExitFocusMode?.();
        return;
    }

    const currentPair = !isPlaybackBeyondPairs ? currentPlaybackOrder[currentSentenceIndex] : null;

    switch (playbackState) {
      case "announcing_question_cue_before_russian":
        if (!currentPair) { setPlaybackState("finished"); if (onSequenceFinished) onSequenceFinished(); onExitFocusMode?.(); return; }
        speak(QUESTION_CUE, 'ru-RU', () => {
          if (isMountedRef.current && !isUserPaused) setPlaybackState("paused_after_question_cue_before_russian");
        });
        break;

      case "paused_after_question_cue_before_russian":
        if (!currentPair) { setPlaybackState("finished"); if (onSequenceFinished) onSequenceFinished(); onExitFocusMode?.(); return; }
        if (pauseTimeoutRef.current) clearTimeout(pauseTimeoutRef.current);
        pauseTimeoutRef.current = window.setTimeout(() => {
          if (isMountedRef.current && !isUserPaused) setPlaybackState("playing_russian");
        }, QUESTION_CUE_PAUSE_DURATION_MS);
        break;

      case "playing_russian":
        if (!currentPair) { setPlaybackState("finished"); if (onSequenceFinished) onSequenceFinished(); onExitFocusMode?.(); return; }
        speak(currentPair.russian, 'ru-RU', () => {
          if (isMountedRef.current && !isUserPaused) setPlaybackState("paused_after_russian_before_english");
        });
        break;

      case "paused_after_russian_before_english":
        if (!currentPair) { setPlaybackState("finished"); if (onSequenceFinished) onSequenceFinished(); onExitFocusMode?.(); return; } 
        if (pauseTimeoutRef.current) clearTimeout(pauseTimeoutRef.current);

        // 1. Voice Recognition Feature
        if (isContinueAfterTranslationEnabled) {
          const SpeechRecognition = (window as unknown as IWindow).SpeechRecognition || (window as unknown as IWindow).webkitSpeechRecognition;

          if (SpeechRecognition) {
            setIsListening(true);
            const recognition = new SpeechRecognition();
            recognitionRef.current = recognition;
            recognition.continuous = false;
            recognition.interimResults = false;
            recognition.lang = 'en-US'; 

            let speechDetected = false;

            recognition.onspeechend = () => {
              speechDetected = true;
            };

            recognition.onerror = (e: any) => {
               if (e.error === 'no-speech') {
                 // Do not set error or pause here.
                 // Silence detected, 'onend' will fire next, and we'll restart there.
               } else {
                 console.warn("Speech recognition error", e);
                 // For errors other than silence (like permission denied), we pause.
                 // Aborted is common during React cleanup, ignore it.
                 if (e.error !== 'aborted') {
                   setIsUserPaused(true);
                   stateBeforeUserPauseRef.current = "paused_after_russian_before_english";
                 }
               }
            };

            recognition.onend = () => {
               // Only proceed if this instance is still active
               if (recognitionRef.current !== recognition) return;

               if (speechDetected) {
                 // Speech was detected and finished
                 setIsListening(false);
                 recognitionRef.current = null;
                 pauseTimeoutRef.current = window.setTimeout(() => {
                    if (isMountedRef.current && !isUserPaused) {
                       setPlaybackState("playing_english");
                    }
                  }, 1000); 
               } else {
                 // No speech detected (likely 'no-speech' error / timeout)
                 // Restart listening if we are still in the state and not paused
                 if (isMountedRef.current && !isUserPaused && playbackState === "paused_after_russian_before_english") {
                    try {
                        recognition.start();
                    } catch (e) {
                        console.error("Failed to restart speech recognition", e);
                        setIsUserPaused(true);
                        stateBeforeUserPauseRef.current = "paused_after_russian_before_english";
                    }
                 }
               }
            };

            try {
              recognition.start();
            } catch (err) {
               console.error("Failed to start speech recognition", err);
               setIsUserPaused(true);
            }
            return; // Return early, skipping standard timer
          } else {
            console.warn("Speech Recognition API not supported in this browser.");
            // Fallthrough to standard logic if not supported
          }
        }

        // 2. Manual Pause Feature ("Make Pause")
        // If "Make Pause" is enabled (and we aren't using the voice feature above),
        // we pause IMMEDIATELY. We do NOT wait for the timer.
        if (isMakePauseEnabled) {
            stateBeforeUserPauseRef.current = "paused_after_russian_before_english";
            setIsUserPaused(true);
            return; // Return early, skipping timer calculation
        }

        // 3. Standard Automatic Timer Logic
        const basePauseMs = basePauseDuration * 1000; 
        let totalCalculatedPauseMs = basePauseMs;

        if (isDynamicPauseEnabled) {
          const russianSentenceLength = currentPair.russian.length;
          const dynamicPortionMs = russianSentenceLength * PER_CHAR_PAUSE_MS;
          totalCalculatedPauseMs = Math.min(
            MAX_PAUSE_MS, 
            basePauseMs + dynamicPortionMs
          );
        }
        lastCalculatedPauseMsRef.current = totalCalculatedPauseMs;

        pauseTimeoutRef.current = window.setTimeout(() => {
          if (isMountedRef.current && !isUserPaused) {
             setPlaybackState("playing_english");
          }
        }, totalCalculatedPauseMs);
        break;

      case "playing_english":
        if (!currentPair) { setPlaybackState("finished"); if (onSequenceFinished) onSequenceFinished(); onExitFocusMode?.(); return; }
        const englishAfterMetadataRemoval = removeLeadingMetadata(currentPair.english);
        let englishTextForSpeech = removeDigits(englishAfterMetadataRemoval);

        if (englishTextForSpeech.trim() === '') {
            console.warn(`English text for speech is empty after processing "${currentPair.english}". Using original text minus metadata, or placeholder.`);
            englishTextForSpeech = englishAfterMetadataRemoval.trim() || "[empty english sentence]";
        }

        speak(englishTextForSpeech, 'en-US', () => {
          if (isMountedRef.current && !isUserPaused) {
            const nextIndex = currentSentenceIndex + 1;
            if (nextIndex < currentPlaybackOrder.length) {
              setCurrentSentenceIndex(nextIndex);
              const nextPair = currentPlaybackOrder[nextIndex];
              const nextEnglishAfterMetadata = removeLeadingMetadata(nextPair.english);
              if (nextEnglishAfterMetadata.endsWith('?')) {
                setPlaybackState("announcing_question_cue_before_russian");
              } else {
                setPlaybackState("playing_russian"); 
              }
            } else {
              setCurrentSentenceIndex(nextIndex); // Ensure index reaches total for 100% progress
              setPlaybackState("finished");
              if (onSequenceFinished) onSequenceFinished();
              onExitFocusMode?.();
            }
          }
        });
        break;
      default: 
        break;
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [playbackState, currentSentenceIndex, currentPlaybackOrder, speak, canUseSpeechSynthesis, basePauseDuration, isDynamicPauseEnabled, isMakePauseEnabled, isContinueAfterTranslationEnabled, isUserPaused, onExitFocusMode, onSequenceFinished]);


  const handlePauseResume = useCallback(() => {
    if (!canUseSpeechSynthesis) return;
    setAudioError(null);

    if (isUserPaused) { 
      window.speechSynthesis.resume(); 

      let newPlaybackState: PlaybackState | null = null;

      if (stateBeforeUserPauseRef.current === "paused_after_question_cue_before_russian") {
        if (pauseTimeoutRef.current) clearTimeout(pauseTimeoutRef.current);
        pauseTimeoutRef.current = null;
        if (currentPlaybackOrder && currentPlaybackOrder[currentSentenceIndex]) {
          newPlaybackState = "playing_russian";
        } else {
          newPlaybackState = "finished";
          if (onSequenceFinished) onSequenceFinished();
          onExitFocusMode?.();
        }
      } else if (stateBeforeUserPauseRef.current === "paused_after_russian_before_english") {
        if (pauseTimeoutRef.current) clearTimeout(pauseTimeoutRef.current);
        pauseTimeoutRef.current = null;
        if (currentPlaybackOrder && currentPlaybackOrder[currentSentenceIndex]) {
          // Check if we should go back to listening or play english
          if (isContinueAfterTranslationEnabled) {
             // Go back to this state to restart listener
             newPlaybackState = "paused_after_russian_before_english";
          } else {
             // Standard behavior: proceed
             newPlaybackState = "playing_english";
          }
        } else {
          newPlaybackState = "finished";
          if (onSequenceFinished) onSequenceFinished();
          onExitFocusMode?.();
        }
      }

      stateBeforeUserPauseRef.current = null; 

      if (newPlaybackState) {
        setPlaybackState(newPlaybackState);
      }
      setIsUserPaused(false); 
    } else { 
      stateBeforeUserPauseRef.current = playbackState; 
      window.speechSynthesis.pause();
      if (recognitionRef.current) {
          recognitionRef.current.abort();
          setIsListening(false);
      }
      setIsUserPaused(true);
    }
  }, [canUseSpeechSynthesis, isUserPaused, playbackState, currentPlaybackOrder, currentSentenceIndex, onExitFocusMode, isContinueAfterTranslationEnabled, onSequenceFinished]);


  const handleDownloadScript = () => {
    if (!sentencePairs || sentencePairs.length === 0) return;

    const scriptContent = sentencePairs
      .map(p => {
        const processedEnglish = removeDigits(removeLeadingMetadata(p.english));
        return `ENG: ${processedEnglish}\nRUS: ${p.russian}`;
      })
      .join('\n---\n');

    const blob = new Blob([scriptContent], { type: 'text/plain;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = 'bilingual_script_eduaudio.txt';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const getStatusMessage = useCallback(() => {
    if (!currentPlaybackOrder || currentPlaybackOrder.length === 0) {
      if (playbackState === "finished") return "Playback finished.";
      if (playbackState === "idle") {
        return isUserPaused ? "User Paused. Ready to play." : "Ready to play.";
      }
      return "Preparing...";
    }

    if (playbackState === "finished") {
        return "Playback finished.";
    }
    // After this point, we know state is not 'finished'.
    if (currentSentenceIndex >= currentPlaybackOrder.length) {
        // If we're past the last sentence but not yet 'finished', we're wrapping up.
        return "Finalizing...";
    }

    const currentPair = currentPlaybackOrder[currentSentenceIndex];
    if (!currentPair) return "Waiting..."; // Should not happen if checks above are correct

    const englishAfterMetadata = removeLeadingMetadata(currentPair.english);
    const englishTextForStatus = removeDigits(englishAfterMetadata) || "[empty english sentence]";

    if (isUserPaused) {
      const relevantStateForUserPause = stateBeforeUserPauseRef.current || playbackState;
      switch (relevantStateForUserPause) {
        case "announcing_question_cue_before_russian":
        case "paused_after_question_cue_before_russian": 
          return `"${QUESTION_CUE.trim()}" (Next: "${currentPair.russian}")`; 
        case "playing_russian": 
          return `"${currentPair.russian}"`;
        case "paused_after_russian_before_english": 
            return `"${currentPair.russian}" (Next: "${englishTextForStatus}")`;
        case "playing_english": 
          return `"${englishTextForStatus}"`;
        case "finished":
          return "Playback finished.";
        case "idle":
        default:
          if (playbackState === "idle") return "User Paused. Ready to play.";
          if (currentPair && currentPair.russian) return `"${currentPair.russian}"`;
          return "Paused.";
      }
    }

    if (isListening) {
      return `Listening for your translation...`;
    }

    switch (playbackState) {
      case "announcing_question_cue_before_russian":
        return `Announcing: "${QUESTION_CUE.trim()}"`;
      case "paused_after_question_cue_before_russian":
        return `Pausing for ${QUESTION_CUE_PAUSE_DURATION_MS / 1000}s...`;
      case "playing_russian":
        return `Playing Russian: "${currentPair.russian}"`;
      case "paused_after_russian_before_english":
        if (currentPlaybackOrder && currentPlaybackOrder[currentSentenceIndex]) {
            const pairForDisplay = currentPlaybackOrder[currentSentenceIndex];
            const baseMs = basePauseDuration * 1000;
            let displayMs = baseMs;
            if (isDynamicPauseEnabled) {
                const dynamicMs = pairForDisplay.russian.length * PER_CHAR_PAUSE_MS;
                displayMs = Math.min(MAX_PAUSE_MS, baseMs + dynamicMs);
            }
            return `Pausing for ${(displayMs / 1000).toFixed(1)}s...`;
        }
        return "Pausing...";
      case "playing_english":
        return `Playing English: "${englishTextForStatus}"`;
      case "idle":
        return "Ready to play.";
      default:
        return "Waiting...";
    }
  }, [currentPlaybackOrder, playbackState, currentSentenceIndex, isUserPaused, basePauseDuration, isDynamicPauseEnabled, isListening]); 


  if (!sentencePairs || sentencePairs.length === 0) return null;

  const isPlaybackConsideredActive = playbackState !== "idle" && playbackState !== "finished";
  const canPauseResume = isPlaybackConsideredActive || isUserPaused;

  const pauseResumeBaseClasses = "flex-1 flex items-center justify-center border rounded-md transition-all duration-150 ease-in-out disabled:opacity-50 disabled:cursor-not-allowed";
  const pauseResumeColorClasses = isUserPaused 
    ? "border-yellow-500 text-yellow-400 hover:bg-yellow-500 hover:text-slate-900" 
    : "border-orange-500 text-orange-400 hover:bg-orange-500 hover:text-slate-900";

  const pauseResumeSizeClasses = isPlaybackConsideredActive
    ? (isFocusMode ? 'text-6xl font-semibold' : 'px-24 py-16 text-6xl font-semibold')
    : "px-4 py-2 text-base"; 

  const stopButtonSizeClasses = isPlaybackConsideredActive
    ? "px-5 py-3 text-lg font-semibold" 
    : "px-4 py-2 text-base"; 

  const iconSizeClasses = isPlaybackConsideredActive 
    ? "w-14 h-14 mr-6" 
    : "w-5 h-5 mr-2"; 

  const statusMessageSizeClasses = isPlaybackConsideredActive
    ? "text-2xl py-2 font-semibold" 
    : "text-sm"; 

  let statusText = getStatusMessage();
  if (!isUserPaused && playbackState !== "idle" && playbackState !== "finished") { // Add "Status:" prefix only when actively playing/processing
      statusText = `Status: ${statusText}`;
  }


  return (
    <div className={isFocusMode ? 'flex flex-col h-full' : 'mt-6 p-4 bg-slate-700/50 border border-slate-600 rounded-lg'}>
      {!isFocusMode && <h3 className="text-lg font-semibold mb-3 text-sky-300">Audio Playback Controls</h3>}
      <div className={isFocusMode ? 'flex flex-col flex-1 space-y-4 justify-center' : 'flex flex-col sm:flex-row space-y-3 sm:space-y-0 sm:space-x-3'}>
        {canUseSpeechSynthesis ? (
          <>
            <button
              onClick={handlePlay}
              disabled={isPlaybackConsideredActive || isUserPaused} 
              className={`${isFocusMode ? '' : 'flex-1'} flex items-center justify-center px-4 py-2 border border-green-500 text-green-400 rounded-md hover:bg-green-500 hover:text-slate-900 disabled:opacity-50 disabled:cursor-not-allowed transition-colors text-base`}
              aria-label="Play sequence: (Optional 'Вопрос' cue & pause) -> Russian sentence -> Pause -> English sentence"
            >
              <PlayIcon className="w-5 h-5 mr-2" /> Play Sequence
            </button>
            <button
              onClick={handlePauseResume}
              disabled={!canPauseResume}
              className={`${pauseResumeBaseClasses} ${pauseResumeColorClasses} ${pauseResumeSizeClasses}`}
              aria-label={isUserPaused ? "Resume audio playback" : "Pause audio playback"}
            >
              {isUserPaused ? <PlayIcon className={iconSizeClasses} /> : <PauseIcon className={iconSizeClasses} />}
              {isUserPaused ? 'Resume' : 'Pause'}
            </button>
            <button
              onClick={handleStop}
              disabled={!isPlaybackConsideredActive && playbackState !== 'finished' && !isUserPaused} 
              className={`${isFocusMode ? '' : 'flex-1'} flex items-center justify-center border border-red-500 text-red-400 rounded-md hover:bg-red-500 hover:text-slate-900 disabled:opacity-50 disabled:cursor-not-allowed transition-colors ${stopButtonSizeClasses}`}
              aria-label="Stop audio playback sequence"
            >
              <StopIcon className={isPlaybackConsideredActive ? "w-6 h-6 mr-2.5" : "w-5 h-5 mr-2"} /> Stop
            </button>
          </>
        ) : (
          <p className="text-sm text-amber-400 p-2 bg-amber-900/50 rounded-md">
            Browser Text-to-Speech is not available. You can still download the script.
          </p>
        )}
        {!isFocusMode && (
          <button
            onClick={handleDownloadScript}
            className={'flex-1 flex items-center justify-center px-4 py-2 border border-sky-500 text-sky-400 rounded-md hover:bg-sky-500 hover:text-slate-900 transition-colors disabled:opacity-50 text-base'}
            aria-label="Download bilingual ENG/RUS script as a text file"
            disabled={isPlaybackConsideredActive || isUserPaused}
          >
            <DownloadIcon className="w-5 h-5 mr-2" /> Download Script
          </button>
        )}
      </div>

      {/* Progress Bar, Status Message, and Error Message Section */}
      {canUseSpeechSynthesis &&
        ((currentPlaybackOrder && currentPlaybackOrder.length > 0) || audioError) && (
        <div className={`mt-3 ${isPlaybackConsideredActive ? "pt-1" : ""}`}>
          {/* Progress Bar: Show if playback is active, paused, or finished */}
          {currentPlaybackOrder && currentPlaybackOrder.length > 0 && 
           (isPlaybackConsideredActive || isUserPaused || playbackState === 'finished') && (
            <ProgressBar
              current={currentSentenceIndex} // Will be total length when 'finished'
              total={currentPlaybackOrder.length}
              label="Sentence Pair Playback Progress"
            />
          )}

          {/* Status Message: Show if not idle (i.e., playing, paused, or finished message active) or if user is paused */}
          {(playbackState !== "idle" || isUserPaused) && (
            <p 
              className={`text-slate-300 transition-all duration-150 ease-in-out ${statusMessageSizeClasses} ${
                // Add margin-top if progress bar is also visible
                (currentPlaybackOrder && currentPlaybackOrder.length > 0 && (isPlaybackConsideredActive || isUserPaused || playbackState === 'finished')) ? 'mt-2' : ''
              }`} 
              aria-live="polite"
            >
              {statusText}
            </p>
          )}

          {/* Audio Error */}
          {audioError && (
            <p className="mt-2 text-sm text-red-300 p-2 bg-red-700/30 border border-red-600 rounded-md" role="alert">
              <strong>Audio Error:</strong> {audioError}
            </p>
          )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useCallback, useEffect, useRef, useMemo } from 'react';
import { ScriptDisplay } from './components/ScriptDisplay';
import { AudioControls } from './components/AudioControls';
import { LoadingSpinner } from './components/LoadingSpinner';
